// ❌ BAD: No wait, throws NoSuchElementException if page is slow
WebElement slowButton = driver.findElement(By.id("delayed-btn"));
slowButton.click();

// ✅ GOOD: Use Explicit Wait to prevent the exception
WebDriverWait wait = new WebDriverWait(driver, Duration.ofSeconds(10));
WebElement button = wait.until(ExpectedConditions.presenceOfElementLocated(By.id("delayed-btn")));
button.click();
